### src/job-store.mjs
export class JobStore {
  #jobs = new Map();

  enqueue(id, payload) {
    if (this.#jobs.has(id)) {
      throw new Error(`job already exists: ${id}`);
    }

    this.#jobs.set(id, {
      id,
      payload,
      status: 'queued',
      attempt: 0,
      result: null,
      lastError: null
    });
  }

  claim() {
    const job = [...this.#jobs.values()].find((entry) => entry.status === 'queued');
    if (!job) {
      return null;
    }

    job.status = 'running';
    job.attempt += 1;
    job.lastError = null;

    return {
      id: job.id,
      payload: job.payload,
      attempt: job.attempt
    };
  }

  requeueRunning(id, reason = 'watchdog requeue') {
    const job = this.#jobs.get(id);
    if (!job || job.status !== 'running') {
      return false;
    }

    job.status = 'queued';
    job.lastError = reason;
    return true;
  }

  complete(id, attempt, result) {
    const job = this.#jobs.get(id);
    if (!job || job.status !== 'running' || job.attempt !== attempt) {
      return false;
    }

    job.status = 'succeeded';
    job.result = result;
    job.lastError = null;
    return true;
  }

  fail(id, error) {
    const job = this.#jobs.get(id);
    if (!job || job.status !== 'running') {
      return false;
    }

    job.status = 'queued';
    job.lastError = error instanceof Error ? error.message : String(error);
    return true;
  }

  get(id) {
    const job = this.#jobs.get(id);
    return job ? { ...job } : null;
  }
}


